954	                q7_t      inA1 = *pA++;
955	                q15_t     inB1 = *pB++;
956	                sum += inA1 * inB1;
957	                colCnt--;
958	            }
959	            *pOut++ = (q7_t) NDS_DSP_SATS((sum >> out_rshift), 8);
960	        }
961	    }
962	#else
963	    uint16_t  i, j, k, l, m, n;
