25	//// Convolution Functions
26	int32_t riscv_nn_conv_HWC_s8_s8_s8_RGB_sft_bias(const q7_t * in_tensor,
27	                               const uint16_t in_tensor_dim,
28	                               const q7_t * ker_weight,
29	                               const uint16_t out_tensor_ch,
30	                               const uint16_t ker_dim,
31	                               const uint16_t pad,
32	                               const uint16_t stride,
33	                               const q7_t * bias,
34	                               const uint16_t bias_lshift,
35	                               const uint16_t out_rshift,
36	                               q7_t * out_tensor,
37	                               const uint16_t out_tensor_dim,
38	                               q15_t * in_tmp_buf,
39	                               q7_t * tmp_buf)
40	{
41	#ifdef ENA_EMPTY_FUN
42	    //empty body
43	#elif defined(ENA_VEC_ISA) && defined(ENA_VEC_INTRINSIC)
44	    int16_t   i_out_y, i_out_x, i_ker_y, i_ker_x;
45	
46	    /*
47	     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
48	     *  im2col are done to output in q15_t format from q7_t input
49	     */
50	    q7_t *wt_tmp = (q7_t*)ker_weight;
51	    q7_t *pBuffer = (q7_t *)in_tmp_buf;
52	    q7_t *pOut = out_tensor;
53	    q7_t *pBufferB = tmp_buf;
54	    uint32_t i;
55	
56	    uint16_t totalsize = 3 * ker_dim * ker_dim;
57	    for (i = 0; i < out_tensor_ch; i++)
58	    {
59	        uint32_t size = totalsize;
60	        while (size > 0)
61	        {
62	            int32_t vl;
63	            vl = __riscv_vsetvl_e8m1(size);
64	            vint8m1_t vWt_tmp = __riscv_vle8_v_i8m1(wt_tmp, vl);
65	            __riscv_vse8(pBufferB, vWt_tmp, vl);
66	            wt_tmp += vl;
67	            pBufferB += vl;
68	            size -= vl;
69	        }
70	        *pBufferB++ = 0;
71	    }
72	
73	    uint32_t buf_len = (3 * ker_dim * ker_dim + 1);
74	    unsigned vl;
75	    vl = __riscv_vsetvl_e8m1(buf_len);
76	    vint8m1_t vZero = __riscv_vand(__riscv_vundefined_i8m1(), 0, vl);   //zero
77	
78	    // This part implements the im2col function
79	    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
80	    {
81	        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
82	        {
83	            //init in_tmp_buf
84	            uint32_t len = buf_len;
85	            q7_t *pBuffer2 = pBuffer;
86	            while (len > 0)
87	            {
88	                vl = __riscv_vsetvl_e8m1(len);
89	                __riscv_vse8(pBuffer2, vZero, vl);
90	                len -= vl;
91	                pBuffer2 += vl;
92	            }
93	
94	            // if (i_ker_y < 0)
95	            for (i_ker_y = i_out_y * stride - pad; i_ker_y < 0; i_ker_y++)
96	            {
97	                pBuffer += ker_dim * 3;
98	            }
99	
100	            int16_t bound_y = ((i_out_y * stride - pad + ker_dim) < in_tensor_dim) ? (i_out_y * stride - pad + ker_dim) : in_tensor_dim;
101	            for (; i_ker_y < bound_y; i_ker_y++)
102	            {
103	                // if (i_ker_x < 0)
104	                for (i_ker_x = i_out_x * stride - pad; i_ker_x < 0; i_ker_x++)
105	                {
106	                    pBuffer += 3;
107	                }
108	
109	                uint16_t bound_x = (i_out_x * stride - pad + ker_dim < in_tensor_dim) ? (i_out_x * stride - pad + ker_dim) : in_tensor_dim;
110	                const q7_t *pPixel = in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * 3;
111	                uint32_t loop = (bound_x - i_ker_x) * 3;
112	                i_ker_x = bound_x;
113	                while (loop > 0)
114	                {
115	                    vl = __riscv_vsetvl_e8m1(loop);
116	                    vint8m1_t vpPixel = __riscv_vle8_v_i8m1(pPixel, vl);
117	                    __riscv_vse8(pBuffer, vpPixel, vl);
118	                    pPixel += vl;
119	                    pBuffer += vl;
120	                    loop -= vl;
121	                }
122	
123	                // if (i_ker_x >= in_tensor_dim)
124	                for ( ; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
125	                {
126	                    pBuffer += 3;
127	                }
128	            }
129	
130	            // if (i_ker_y >= in_tensor_dim)
131	            for (; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
132	            {
133	                pBuffer += ker_dim * 3;
134	            }
135	            pBuffer++;
136	
137	            if (pBuffer == (q7_t *)in_tmp_buf + 2 * (3 * ker_dim * ker_dim + 1))
138	            {
139	                pOut = nn_mat_mul_kernel_q7((q7_t *)tmp_buf, (q7_t *)in_tmp_buf, out_tensor_ch, 3 * ker_dim * ker_dim + 1, bias_lshift, out_rshift, bias, pOut);
140	                pBuffer = (q7_t *)in_tmp_buf;
141	            }
142	        }
143	    }
144	
145	#if (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD)
146	    if (pBuffer != (q7_t *)in_tmp_buf)
147	    {
148	        unsigned vl;
149	        const q7_t *p_wt = ker_weight;
150	        int       i;
151	        uint16_t  colCnt = 3 * ker_dim * ker_dim;
152	        // long vlenb = NDS_VEC_CSR_GET_VLENB();
153	
154	        vl = __riscv_vsetvl_e32m1(1);
155	        vint32m1_t vZero = __riscv_vand(__riscv_vundefined_i32m1(), 0x0, vl);     //const zero for redsum
156	
157	        for (i = 0; i < out_tensor_ch; i++)
158	        {
159	            q7_t      *p_in = (q7_t*)in_tmp_buf;
160	            uint16_t colCnt2 = colCnt;
161	
162	            //clear v0~v7
163	            vl = __riscv_vsetvl_e32m8(colCnt);
164	            vint32m8_t vAccumulator = __riscv_vand(__riscv_vundefined_i32m8(), 0x0, vl);
165	
166	            // while (colCnt2 >= (vlenb * NDS_VEC_VTYPE_LMUL_ID_M8))
167	            // {
168	            //     NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
169	            //     //load src1
170	            //     NDS_VEC_VLB_V(NDS_VEC_V8, p_wt);
171	            //     //load src2
172	            //     NDS_VEC_VLB_V(NDS_VEC_V16, p_in);
173	            //     //bump pointers and update loop counter
174	            //     colCnt2 -= vl;
175	            //     p_wt += vl;
176	            //     p_in += vl;
177	            //     //set the proper avl/SEW/LMUL values for vd4dot
178	            //     vl >>= 2;
179	            //     NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
180	            //     //acc += src1 * src2
181	            //     NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
182	            // }
183	
184	            //extra process for the case of vd4dot's avl is not a mutiple of 4
185	            while(colCnt2 > 0)
186	            {
187	                //clean one of the dot product source
188	                vl = __riscv_vsetvlmax_e8m8();
189	                vint8m8_t vP_wt_i8m8 = __riscv_vand(__riscv_vundefined_i8m8(), 0, vl);
190	
191	                vl = __riscv_vsetvl_e8m8(colCnt2);
192	                //load src1
193	                vP_wt_i8m8 = __riscv_vle8_v_i8m8_tu(vP_wt_i8m8, p_wt, vl);
194	                //load src2
195	                vint8m8_t vP_in_i8m8 = __riscv_vle8_v_i8m8(p_in, vl);
196	                //bump pointers and update loop counter
197	                colCnt2 -= vl;
198	                p_wt += vl;
199	                p_in += vl;
200	                //set the proper avl/SEW/LMUL values for vd4dot
201	                //remember to deal with the avl of vd4dot is not a multiple of 4 case
202	                vl = __riscv_vsetvl_e32m8(vl);
203	                //acc += src1 * src2
204	                vAccumulator = __riscv_vd4dots_vv_i32m8(vAccumulator, vP_wt_i8m8, vP_in_i8m8, vl);
205	            }
206	
207	            vl = __riscv_vsetvl_e32m8(colCnt);  //note the avl here
208	            vint32m1_t vSum = __riscv_vredsum(vAccumulator, vZero, vl);
209	
210	            //add bias back
211	            vl = __riscv_vsetvl_e32m1(1);
212	            vint8mf4_t vBias_i8mf4 = __riscv_vle8_v_i8mf4(bias, vl);
213	            vint32m1_t vBias_i32m1 = __riscv_vsext_vf4(vBias_i8mf4, vl);
214	            vBias_i32m1 = __riscv_vsll(vBias_i32m1, bias_lshift, vl);
215	            vBias_i32m1 = __riscv_vadd(vBias_i32m1, NN_ROUND(out_rshift), vl);
216	            vSum = __riscv_vadd(vSum, vBias_i32m1, vl);
217	
218	            //scale down, clip and store the results
219	            vl = __riscv_vsetvl_e16mf2(1);
220	            vint16mf2_t vSum_i16mf2 = __riscv_vnsra(vSum, out_rshift, vl);
221	            vl = __riscv_vsetvl_e8mf4(1);
222	            vint8mf4_t vSum_i8mf4 = __riscv_vnclip(vSum_i16mf2, 0, __RISCV_VXRM_RNU, vl);
223	            __riscv_vse8(pOut, vSum_i8mf4, vl);
224	
225	            bias += vl;
226	            pOut += vl;
227	        }
228	    }
229	#elif (NDS_VEC_RVV_VERSION >= 100)
230	    /* left-over because odd number of output pixels */
231	    if (pBuffer != (q7_t *)in_tmp_buf)
232	    {
233	        const q7_t *pA = ker_weight;
234	        int i;
235	        /* basically each time it process 4 entries */
236	        uint16_t colCnt = (3 * ker_dim * ker_dim);
237	
238	        //set SEW for 1st time VMV_S_X
239	        //LMUL=8 is just for clear v8~v15 (vmv ignores LMUL)
240	        vl = __riscv_vsetvl_e32m8(colCnt);
241	
242	        for (i = 0; i < out_tensor_ch; i++)
243	        {
244	            q31_t sum = ((q31_t)bias[i] << bias_lshift) + NN_ROUND(out_rshift);
245	            q7_t *pB = (q7_t*)in_tmp_buf;
246	            uint16_t colCnt2 = colCnt;
247	
248	            //init
249	            vint32m1_t vBias = __riscv_vmv_s_x_i32m1(sum, vl);
250	            //clear v8~v15 (acc)
251	            vint32m8_t vAcc = __riscv_vundefined_i32m8();
252	            vAcc = __riscv_vand_tu(vAcc, vAcc, 0, vl);
253	
254	            while (colCnt2 > 0)
255	            {
256	                vl = __riscv_vsetvl_e8m2(colCnt2);
257	                vint8m2_t vPa_i8 = __riscv_vundefined_i8m2();
