730	            q15_t    *pB = in_tmp_buf;
731	            /* basically each time it process 4 entries */
732	            uint16_t  colCnt = 3 * ker_dim * ker_dim >> 2;
733	
734	            while (colCnt)
735	            {
736	
737	                q31_t     inA1, inA2;
738	                q31_t     inB1, inB2;
739	
740	                pA = (q7_t *) read_and_pad((void *)pA, &inA1, &inA2);
741	
742	                inB1 = *__SIMD32(pB)++;
743	                sum = NDS_DSP_KMADA(sum, inA1, inB1);
744	                inB2 = *__SIMD32(pB)++;
745	                sum = NDS_DSP_KMADA(sum, inA2, inB2);
746	
747	                colCnt--;
748	            }
749	            colCnt = 3 * ker_dim * ker_dim & 0x3;
750	            while (colCnt)
751	            {
752	                q7_t      inA1 = *pA++;
753	                q15_t     inB1 = *pB++;
754	                sum += inA1 * inB1;
755	                colCnt--;
756	            }
757	            *pOut++ = (q7_t) NDS_DSP_SATS((sum >> out_rshift), 8);
758	        }
759	    }
760	#else
761	
762	    uint16_t  i, j, k, l, m, n;
763	    int       conv_out;
764	    long in_row, in_col;
765	
766	    for (i = 0; i < out_tensor_ch; i++)
767	    {
768	        for (j = 0; j < out_tensor_dim; j++)
769	        {
770	            for (k = 0; k < out_tensor_dim; k++)
771	            {
772	                conv_out = (bias[i] << bias_lshift) + NN_ROUND(out_rshift);
773	                for (m = 0; m < ker_dim; m++)
774	                {
775	                    for (n = 0; n < ker_dim; n++)
776	                    {
777	                        /* if-for implementation */
778	                        in_row = stride * j + m - pad;
779	                        in_col = stride * k + n - pad;
780	                        if (in_row >= 0 && in_col >= 0 && in_row < in_tensor_dim && in_col < in_tensor_dim)
781	                        {
782	                            for (l = 0; l < 3; l++)
783	                            {
784	                                conv_out +=
785	                                    in_tensor[(in_row * in_tensor_dim + in_col) * 3 +
786	                                              l] * ker_weight[i * 3 * ker_dim * ker_dim + (m * ker_dim +
787	                                                              n) * 3 + l];
788	                            }
789	                        }
790	                    }
791	                }
792	                out_tensor[i + (j * out_tensor_dim + k) * out_tensor_ch] = (q7_t) NDS_ISA_SATS((conv_out >> out_rshift), 8);
793	            }
794	        }
795	    }
796	
797	#endif                          /* ENA_DSP_ISA */
798	
799	    return 0;
800	}
